    40	typedef enum { HO_CTX_BOTH, HO_CTX_SOURCE, HO_CTX_TARGET } ho_ctx_type_t;
    41	static nr_handover_context_t *alloc_ho_ctx(ho_ctx_type_t type)
    42	{
    43	  nr_handover_context_t *ho_ctx = calloc(1, sizeof(*ho_ctx));
    44	  AssertFatal(ho_ctx != NULL, "out of memory\n");
    45	  if (type == HO_CTX_SOURCE || type == HO_CTX_BOTH) {
    46	    ho_ctx->source = calloc(1, sizeof(*ho_ctx->source));
    47	    AssertFatal(ho_ctx->source != NULL, "out of memory\n");
    48	  }
    49	  if (type == HO_CTX_TARGET || type == HO_CTX_BOTH) {
    50	    ho_ctx->target = calloc(1, sizeof(*ho_ctx->target));
    51	    AssertFatal(ho_ctx->target != NULL, "out of memory\n");
    52	  }
    53	  return ho_ctx;
    54	}
